// KACE: JWT Token + kboxid aus Set-Cookie lesen
const response = $input.first().json;
const body = response.body || response;

if (body.errorCode || body.errorDescription) {
  throw new Error('KACE Login failed: ' + (body.errorDescription || body.errorCode));
}

const cookies = response.headers?.['set-cookie'] || [];
const cookieList = Array.isArray(cookies) ? cookies : [cookies];

let token  = null;
let kboxid = null;

for (const cookie of cookieList) {
  const jwtMatch  = cookie.match(/x-kace-auth-jwt=([^;]+)/i);
  const kboxMatch = cookie.match(/kboxid=([^;]+)/i);
  if (jwtMatch)  token  = jwtMatch[1].trim();
  if (kboxMatch) kboxid = kboxMatch[1].trim();
}

if (!token)  throw new Error('x-kace-auth-jwt not found in response cookies!');
if (!kboxid) throw new Error('kboxid not found in response cookies!');

console.log('✅ Token:', token.substring(0, 20) + '...');
console.log('✅ kboxid:', kboxid.substring(0, 10) + '...');

return [{
  json: {
    token,
    kboxid,
    bearerHeader: 'Bearer ' + token,
    cookieHeader: 'kboxid=' + kboxid + '; x-kace-auth-jwt=' + token
  }
}];

