function normalizeFQDN(raw) {
  let h = (raw || '').trim().toLowerCase();
  if (h.endsWith('.lidozrh.ch') && !h.endsWith('.lidozrh.ch.lidozrh.ch')) return h;
  h = h.replace(/\.lidozrh\.ch\.lidozrh\.ch$/, '.lidozrh.ch');
  if (h.endsWith('.lidozrh.ch')) return h;
  h = h.replace(/\.cluster\.local$/, '');
  h = h.replace(/\.lidozrh\.ch\.empty$/, '');
  h = h.replace(/\.lidozrh\.empty$/, '');
  h = h.replace(/\.empty$/, '');
  h = h.replace(/\.workgroup$/i, '');
  h = h.replace(/\.lidozrh$/, '');
  return h.split('.')[0] + '.lidozrh.ch';
}

function extractHostname(raw) {
  return (raw || '').trim().toLowerCase().split('.')[0];
}

function getAssetTypeFromPrefix(hostname) {
  const h = (hostname || '').toUpperCase();
  if (h.startsWith('LIDOZRHL'))  return 'workstation';
  if (h.startsWith('LIDOZRHA'))  return 'workstation';
  if (h.startsWith('LIDOZRHW'))  return 'workstation';
  if (h.startsWith('LIDOZRHM'))  return 'workstation';
  if (h.startsWith('LIDOPCTL'))  return 'workstation';
  if (h.startsWith('LIDOZRHV'))  return 'virtual server';
  if (h.startsWith('LIDOZRHC'))  return 'virtual server';
  if (h.startsWith('LIDOZRHS'))  return 'physical server';
  if (h.startsWith('ZRHSTSW'))   return 'network';
  if (h.startsWith('ZRHBASW'))   return 'network';
  if (h.startsWith('ZRH-NG-FW')) return 'network';
  if (h.startsWith('ZRHSTG'))    return 'physical server';
  return null;
}

function getAssetTypeFromOS(osName, chassisType, model, isVirtual) {
  if (isVirtual) return 'virtual server';
  const ch = (chassisType || '').toLowerCase();
  const m  = (model       || '').toLowerCase();
  if (ch === 'notebook' || ch === 'laptop' ||
      m.includes('latitude') || m.includes('macbook') ||
      m.includes('thinkpad') || m.includes('elitebook')) return 'workstation';
  if (ch === 'desktop' || ch === 'workstation') return 'workstation';
  if ((osName || '').toLowerCase().includes('server')) return 'physical server';
  return 'workstation';
}

function getDataCenter(assetType, hostname) {
  const h = (hostname || '').toUpperCase();
  if (assetType === 'workstation') return '';
  if (h.startsWith('ZRHSTSW'))    return 'LSYFN On premises';
  if (h.startsWith('ZRHBASW'))    return 'LSYFN On premisesr';
  if (assetType === 'virtual server')  return 'LSYFN Atlas Edge (Nugolo)';
  if (assetType === 'physical server') return 'LSYFN On premises';
  if (assetType === 'network')         return 'LSYFN On premises';
  return '';
}

function getITProvider(hostname) {
  const h = (hostname || '').toUpperCase();
  // LIDOPCTL = LSYFN IT Infrastructure
  return 'LSYFN IT Infrastructure';
}

function getEnvironment(hostname, assetType) {
  if (assetType === 'workstation') return 'Prod';
  const h = (hostname || '').toLowerCase();
  if (h.includes('dev') || h.includes('test') ||
      h.includes('uat') || h.includes('stg')) return 'Dev/Test';
  return 'Prod';
}

function getCustomField(asset, fieldNamePart) {
  if (!asset) return '';
  const fields = asset.asset_data || asset.custom_fields || [];
  if (!Array.isArray(fields)) return '';
  const f = fields.find(x => x.name && x.name.toLowerCase().includes(fieldNamePart.toLowerCase()));
  return f ? (f.value || '') : '';
}

