  const key      = (row['hardware name'] || '').toLowerCase().trim();
  const existing = existingMap[key];

  if (existing) {
    const merged = { ...row };
    for (const field of PRESERVE_FIELDS) {
      // Nur aus existing übernehmen wenn NICHT bereits vom ProTack Mapping befüllt
      if (existing[field] && existing[field].toString().trim() !== '' &&
          (!row[field] || row[field].toString().trim() === '')) {
        merged[field] = existing[field];
      }
    }
    mergedRows.push(merged);
    delete existingMap[key];
    cntUpdated++;
  } else {
    mergedRows.push(row);
    cntNew++;
  }
}

